using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the discriminator property from "Discriminator" to "$type".
            // Preserve the EF 8 property name so existing 500K documents remain readable,
            // and raw SQL queries against c.Discriminator keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed the id format from "EntityName|<key>" to just "<key>".
            // Preserve the EF 8 format so existing documents are still addressable.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonPropertyName("id")
                  .HasValueGenerator<ProductIdValueGenerator>();
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // EF Core 9 removed synchronous Cosmos query support.
        // No convention-level fix — all call sites must move to async.
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = "";
}

// Generates ids in the EF 8 format "Product|<key>" for backward compatibility.
class ProductIdValueGenerator : Microsoft.EntityFrameworkCore.ValueGeneration.ValueGenerator<int>
{
    public override bool GeneratesTemporaryValues => false;
    public override int Next(Microsoft.EntityFrameworkCore.ChangeTracking.EntityEntry entry)
        => throw new NotSupportedException("Id must be assigned explicitly.");
}

