class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still references c.Discriminator because we
        // configured HasDiscriminator("Discriminator") to keep the EF 8 property name.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 removed sync Cosmos queries; use async instead.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

