    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // BREAKING CHANGE 4: EF Core 9 removed synchronous Cosmos query execution.
        // All call sites must migrate from .ToList() to .ToListAsync(), etc.
    }
}

